"use strict";(self.webpackChunk_servicenow_sdk_docs=self.webpackChunk_servicenow_sdk_docs||[]).push([["69242"],{220506(e){e.exports=JSON.parse('{"tag":{"label":"UpdateRecord","permalink":"/sdk/4.9.0/tags/update-record","allTagsPath":"/sdk/4.9.0/tags","count":1,"items":[{"id":"guides/playbook-activities-guide","title":"Playbook Activities Guide","description":"An activity is a single step inside a playbook lane \u2014 present a form to a user, send an email, update a record, branch on a condition, and so on. Every step a playbook performs is an activity. This guide covers a representative subset of the built-in activities shipped with the SDK: interactive activities (Instruction, RecordForm, KnowledgeArticle, ChecklistTask, \u2026), automation activities (UpdateRecord, CreateNewRecord, SendEmail, \u2026), approval activities, the Decision branching activity, the RecordList display activity, experience properties, and the stage-level Decision pattern (a Decision placed at the lanes body level rather than inside a lane). The full set of exports lives under src/api/playbook/built-ins/activity-definitions/; for wfa.playbook.activity signatures and the data pill validation matrix see playbook-api.","permalink":"/sdk/4.9.0/guides/playbook-activities-guide"}],"unlisted":false}}')}}]);